import { ExternalVault } from './external-vault';
/**
 * Synchronization credentials with HashiCorp Vault using certificate authentication method
 */
export interface HashicorpCertificate extends ExternalVault {
    /**
     * ID of certificate saved in Dynatrace CV. Using this certificate you can authenticate to your HashiCorp Vault.
     */
    certificate?: string;
    /**
     * Path to folder where credentials in HashiCorp Vault are stored.
     */
    pathToCredentials?: string;
}
